sql:
SELECT first_name, last_name
FROM borrowers
ORDER BY last_name, first_name;

external_knowledge:
- Most recent status update refers to the status with the highest status update count for each loan; 
- Loan details include the loan ID, the total number of payments, the total amount paid, and the average payment amount; 
- Loan status includes the status, status reason, and the officer who last updated the status.

sql:
SELECT department, COUNT(*) AS officer_count
FROM loan_officers
GROUP BY department;

external_knowledge:
- 'Masters of Change' refers to loan officers who have made the most status updates; 
- 'moves' refers to the total number of status updates made by a loan officer; 
- 'games won' refers to the total number of loans managed by a loan officer.

sql:
SELECT DISTINCT lo.name AS loan_officer_name
FROM loan_officers lo
JOIN loan_status ls ON lo.officer_id = ls.status_updated_by;
